    {
      "date": "1731-01-02",
      "tags_section": "Es werden zum Verkauff offerirt",
      "text": "4. Zwey Stücklein vom besten weissen Marggräffer-Wein de Anno 1718, und ein dito von gemeldtem Jahrgang, weisser Elsasser, sehr schön und vom besten Orth, in moderatem Preiß."
    },
    {
      "date": "1731-01-02",
      "tags_section": "Es werden zum Verkauff offerirt",
      "text": "5. Eine zimblich wohl conditionirte Violino di Gamba, so im Adresse-Contor kan gesehen werden."
    },
    {
      "date": "1731-01-02",
      "tags_section": "Es werden zum Verkauff offerirt",
      "text": "6. Bey Herrn Burckhardt zur Linden ist zu haben: Extra guter Muscateller und Languedocker-Wein die Bouteille à 7 1/2 Baken."
    },
    {
      "date": "1731-01-02",
      "tags_section": "Es werden zum Verkauff offerirt",
      "text": "7. Ein grosses Pult, daran drey Persohnen zugleich sizen und schreiben können, sambt darzu gehörigem Tisch."
    },
    {
      "date": "1731-01-02",
      "tags_section": "Es werden zum Verkauff offerirt",
      "text": "8. Ein grosses Himmel-Beth mit einer bespannen Rahmen von Zwilch."
    },
    {
      "date": "1731-01-02",
      "tags_section": "Es werden zum Verkauff offerirt",
      "text": "9. Ein schöner Hauß-schlitten sambt dem Geschirz."
    },
    {
      "date": "1731-01-02",
      "tags_section": "Es werden zum Verkauff offerirt",
      "text": "10. Ein extra schöner Bier-Schildt."
    },
    {
      "date": "1731-01-02",
      "tags_section": "Es werden zum Verkauff offerirt",
      "text": "11. Ein halb Dußend Französische Sessel von grüner Mocquette, wovon im Adresse-Contor ein Muster zu sehen ist."
    },
    {
      "date": "1731-01-02",
      "tags_section": "Es werden zum Verkauff offerirt",
      "text": "12. Fünff Stuck Tapzerey von rother Mocquette, zu Außgarnirung eines Zimmers mittelmäßiger Größe, seind auch im Adresse-Contor zu sehen."
    },
    {
      "date": "1731-01-02",
      "tags_section": "Es werden zum Verkauff offerirt",
      "text": "13. Ein esferner Bräther mittelmäßiger Grösse."
    },
    {
      "date": "1731-01-02",
      "tags_section": "Es werden zum Verkauff offerirt",
      "text": "14. Guter alter Land-Honig, die Maaß à 6. Baken."
    },
    {
      "date": "1731-01-02",
      "tags_section": "Es werden zum Verkauff offerirt",
      "text": "15. Ein extra sauberes Lavoir oder Gießfaß von Englischem Zinn, auff die neue Mode."
    },
    {
      "date": "1731-01-02",
      "tags_section": "Es werden zum Verkauff offerirt",
      "text": "16. Eine sehr artig und wohl-gefütterte leichte Berline."
    },
    {
      "date": "1731-01-02",
      "tags_section": "Es werden zum Verkauff offerirt",
      "text": "17. Eine brave Chaise auff vier Räderen."
    },
    {
      "date": "1731-01-02",
      "tags_section": "Es werden zum Verkauff offerirt",
      "text": "18. Eine brave Behausung von vortrefflicher Situation."
    },
    {
      "date": "1731-01-02",
      "tags_section": "Es werden zum Verkauff offerirt",
      "text": "19. Eine mit Silber guarnirte saubere Canne naturelle."
    },
    {
      "date": "1731-01-02",
      "tags_section": "Es werden zum Verkauff offerirt",
      "text": "20. Zwey kleine Bären-stößlein per Jüngferlein."
    },
    {
      "date": "1731-01-02",
      "tags_section": "Es werden zum Verkauff offerirt",
      "text": "21. Saubere Limmet-Dachten zum Rosenkranz, à 12. Gulden der Zentner."
    },
    {
      "date": "1731-01-02",
      "tags_section": "Es werden zum Verkauff offerirt",
      "text": "22. Ein Englisches Sättelein fast neu, sambt anderm Pferdzeug und Stiefel."
    },
    {
      "date": "1731-01-02",
      "tags_section": "Es werden zum Verkauff offerirt",
      "text": "23. Saubere Flinthen und Pistohlen."
    },
